import { useCallback, useEffect, useReducer, useRef } from 'react';
import { FormMode } from '../../../../../components/form';
import type { JournalEntryHeaderKey } from '../types/journalEntryHeader.types';
import type { JournalEntryLineModel } from '../types/journalEntryLine.types';
import {
  buildJournalLineStatesFromModels,
  initJournalHeaderFields,
  initJournalLineFields,
  journalLineModelFromFields,
  journalLinesFromState,
  newLineId,
} from '../reducer/journalEntryFieldHelpers';
import type { JournalEntryHeaderModel } from '../types/journalEntryHeader.types';
import type { VoucherStatus } from '../../../../../services/kt/models';
import {
  createInitialJournalEntryFormState,
  journalEntryFormReducer,
} from '../reducer/journalEntryFormReducer';

/** IField reducer + flat getters for JournalEntryForm. */
export function useJournalEntryFormState(initialFormMode: FormMode = FormMode.Edit) {
  const [state, dispatch] = useReducer(
    journalEntryFormReducer,
    { formMode: initialFormMode },
    init => ({ ...createInitialJournalEntryFormState(), formMode: init.formMode }),
  );
  const stateRef = useRef(state);

  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const setHeader = useCallback((key: JournalEntryHeaderKey, value: string) => {
    dispatch({ type: 'SET_HEADER', key, value });
  }, []);

  const h = state.header;
  const entryDate = h.entryDate.value;
  const setEntryDate = useCallback((v: string) => setHeader('entryDate', v), [setHeader]);
  const code = h.code.value;
  const setCode = useCallback((v: string) => setHeader('code', v), [setHeader]);
  const description = h.description.value;
  const setDescription = useCallback((v: string) => setHeader('description', v), [setHeader]);
  const referenceNo = h.referenceNo.value;
  const setReferenceNo = useCallback((v: string) => setHeader('referenceNo', v), [setHeader]);
  const referenceCustomerName = h.referenceCustomerName.value;
  const setReferenceCustomerName = useCallback((v: string) => setHeader('referenceCustomerName', v), [setHeader]);
  const processingLevel = h.processingLevel.value;
  const setProcessingLevel = useCallback((v: string) => setHeader('processingLevel', v), [setHeader]);

  const lines = journalLinesFromState(state.lines);
  const setLines = useCallback((next: JournalEntryLineModel[]) => {
    const currentState = stateRef.current;
    dispatch({
      type: 'INIT',
      header: currentState.header,
      lines: next.length > 0
        ? next.map((m, i) => initJournalLineFields(m, currentState.lines[i]?.lineId ?? newLineId()))
        : [initJournalLineFields({
          debitAccountCode: '',
          debitAccountName: '',
          creditAccountCode: '',
          creditAccountName: '',
          amount: 0,
          description: '',
        }, newLineId())],
      status: currentState.meta.status,
    });
  }, []);

  const updateLine = useCallback((idx: number, patch: Partial<JournalEntryLineModel>) => {
    const line = state.lines[idx];
    if (!line) return;
    (Object.keys(patch) as (keyof JournalEntryLineModel)[]).forEach(key => {
      if (patch[key] !== undefined) {
        dispatch({ type: 'SET_LINE', lineId: line.lineId, key, value: patch[key] as string | number });
      }
    });
  }, [state.lines]);

  const addLine = useCallback(() => dispatch({ type: 'ADD_LINE' }), []);
  const insertLineAfter = useCallback((afterIndex: number, model?: JournalEntryLineModel): string => {
    const lineId = newLineId();
    dispatch({ type: 'INSERT_LINE_AFTER', afterIndex, lineId, model });
    return lineId;
  }, []);
  const removeLine = useCallback((index: number) => dispatch({ type: 'REMOVE_LINE', index }), []);

  /** Hủy / revert — INIT lại header + lines từ snapshot (reset IField dirty trong reducer). */
  const applyFormState = useCallback((
    header: JournalEntryHeaderModel,
    lineModels: JournalEntryLineModel[],
    nextStatus: VoucherStatus,
  ) => {
    dispatch({
      type: 'INIT',
      header: initJournalHeaderFields(header),
      lines: buildJournalLineStatesFromModels(lineModels),
      status: nextStatus,
    });
  }, []);

  return {
    state,
    dispatch,
    headerModel: () => ({
      entryDate: h.entryDate.value,
      code: h.code.value,
      description: h.description.value,
      referenceNo: h.referenceNo.value,
      referenceCustomerName: h.referenceCustomerName.value,
      processingLevel: h.processingLevel.value,
    }),
    entryDate,
    setEntryDate,
    code,
    setCode,
    description,
    setDescription,
    referenceNo,
    setReferenceNo,
    referenceCustomerName,
    setReferenceCustomerName,
    processingLevel,
    setProcessingLevel,
    lineRows: state.lines,
    lines,
    setLines,
    updateLine,
    addLine,
    insertLineAfter,
    removeLine,
    applyFormState,
    status: state.meta.status,
    setStatus: useCallback((s: typeof state.meta.status) => {
      dispatch({ type: 'SET_META', patch: { status: s } });
    }, []),
    formMode: state.formMode,
    setFormMode: useCallback((m: FormMode) => {
      dispatch({ type: 'SET_FORM_MODE', formMode: m });
    }, []),
  };
}
